#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>

int main() {
  int server_fd, client_fd;
  struct sockaddr_in server_addr, client_addr;
  socklen_t client_len = sizeof(client_addr);
  char buffer[1024] = {0};

  server_fd = socket(AF_INET, SOCK_STREAM, 0);
  if (server_fd < 0) {
    printf("Soket yaradılmadı\n");
    return 1;
  }

  server_addr.sin_family = AF_INET;
  server_addr.sin_addr.s_addr = INADDR_ANY;
  server_addr.sin_port = htons(8080);

  if (bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
    printf("Bind uğursuz oldu\n");
    return 1;
  }

  if (listen(server_fd, 3) < 0) {
    printf("Listen uğursuz oldu\n");
    return 1;
  }

  printf("Server 8080 portunda gözləyir...\n");
  client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &client_len);
  if (client_fd < 0) {
    printf("Müştəri qəbul edilmədi\n");
    return 1;
  }

  read(client_fd, buffer, 1024);
  printf("Müştəri mesajı: %s\n", buffer);
  char* response = "Salam, müştəri!";
  write(client_fd, response, strlen(response));

  close(client_fd);
  close(server_fd);
  return 0;
}
// Output:
// Server 8080 portunda gözləyir...
// Müştəri mesajı: [müştəridən gələn mesaj]

