  if (bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
    printf("Ошибка привязки\n");
    return 1;
  }

  if (listen(server_fd, 3) < 0) {
    printf("Ошибка прослушивания\n");
    return 1;
  }

  printf("Сервер слушает на порту 8080...\n");
  client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &client_len);
  if (client_fd < 0) {
    printf("Ошибка принятия клиента\n");
    return 1;
  }

  read(client_fd, buffer, 1024);
  printf("Сообщение клиента: %s\n", buffer);
  char* response = "Привет, клиент!";
  write(client_fd, response, strlen(response));

  close(client_fd);
  close(server_fd);
  return 0;
}
// Output:
// Сервер слушает на порту 8080...
// Сообщение клиента: [сообщение от клиента]

